PyTypeObject* DoInitWrapperTextBlock(const UClass* InClass, PyTypeObject* InSuperType, PyObject* InSuperTypes)
{
	if (InClass == nullptr)
	{
		return nullptr;
	}

	if (FUPyWrapperTypeRegistry::Get().HasWrappedClassType(InClass))
	{
		return const_cast<PyTypeObject*>(FUPyWrapperTypeRegistry::Get().GetWrappedClassType(InClass));
	}

	PyTypeObject* PyType = &UPyWrapperTextBlockType;
	PyType->tp_flags = Py_TPFLAGS_DEFAULT | Py_TPFLAGS_BASETYPE;
	PyType->tp_base = InSuperType != nullptr ? InSuperType : &UPyWrapperObjectType;
	PyType->tp_bases = InSuperTypes;
	PyType->tp_methods = FUPyWrapperTextBlockPyMethodDefs;
	PyType->tp_getset = FUPyWrapperTextBlockGetSets;

	if (PyType_Ready(PyType) == 0)
	{
		FUPyWrapperTypeRegistry::Get().RegisterWrappedClassType(InClass, PyType);
		return PyType;
	}

	return nullptr;
}

void InitializeUPyWrapperTextBlock(UPyGenUtil::FNativePythonModule& ModuleInfo)
{
	FUPyWrapperTypeRegistry::Get().RegisterAutoWrappedClassCreateFunc(UTextBlock::StaticClass(), DoInitWrapperTextBlock);
}

FUPyWrapperTextBlock* UPyIsTextBlock(PyObject* InSelf)
{
	if (InSelf && PyObject_IsInstance(InSelf, (PyObject*)&UPyWrapperTextBlockType))
	{
		return (FUPyWrapperTextBlock*)InSelf;
	}
	return nullptr;
}

namespace UPyConversion
{
	FUPyConversionResult Nativize(PyObject* PyObj, UTextBlock*& OutVal, const ESetErrorState SetErrorState)
	{
		if (FUPyWrapperTextBlock* PyTextBlock = UPyIsTextBlock(PyObj))
		{
			if (!FUPyWrapperObject::ValidateInternalState(PyTextBlock))
			{
				return FUPyConversionResult::Failure();
			}

			OutVal = PyTextBlock->ValuePtr();
			return FUPyConversionResult::Success();
		}

		UPYCONVERSION_RETURN(FUPyConversionResult::Failure(), TEXT("Nativize"), *FString::Printf(TEXT("Cannot nativize '%s' as 'UTextBlock'"), *UPyUtil::GetFriendlyTypename(PyObj)));
	}
}
